import{_ as s,c as n,o as a,a4 as l}from"./chunks/framework.HaEZziQ1.js";const m=JSON.parse('{"title":"NodeJS 面试题","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端面试相关/NodeJS面试题/NodeJS面试题.md","filePath":"Document/前端面试相关/NodeJS面试题/NodeJS面试题.md","lastUpdated":1709668918000}'),o={name:"Document/前端面试相关/NodeJS面试题/NodeJS面试题.md"},e=l(`<h1 id="nodejs-面试题" tabindex="-1">NodeJS 面试题 <a class="header-anchor" href="#nodejs-面试题" aria-label="Permalink to &quot;NodeJS 面试题&quot;">​</a></h1><h2 id="浏览器-eventloop-和-node-中的有什么区别" tabindex="-1">浏览器 Eventloop 和 Node 中的有什么区别 <a class="header-anchor" href="#浏览器-eventloop-和-node-中的有什么区别" aria-label="Permalink to &quot;浏览器 Eventloop 和 Node 中的有什么区别&quot;">​</a></h2><p>众所周知 JS 是⻔⾮阻塞单线程语⾔，因为在最初 JS 就是为了和浏览器交互⽽ 诞⽣的。如果 JS 是⻔多线程的语⾔话，我们在多个线程中处理 DOM 就可能会发⽣问题（⼀个线程中新加节点，另⼀个线程中删除节点），当然可以引⼊ 读写锁解决这个问题。</p><p>JS 在执⾏的过程中会产⽣执⾏环境，这些执⾏环境会被顺序的加⼊到执⾏栈中。如果遇到异步的代码，会被挂起并加⼊到 Task （有多种 task ） 队列中。⼀旦执⾏栈为空，Event Loop 就会从 Task 队列中拿出需要执⾏的代码并放⼊执⾏栈中执⾏，所以本质上来说 JS 中的异步还是同步⾏为</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;script start&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#61AFEF;">setTimeout</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#E5C07B;">	console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;setTimeout&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}, </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;script end&#39;</span><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>以上代码虽然 setTimeout 延时为 0 ，其实还是异步。这是因为 HTML5 标准规定这个函数第⼆个参数不得⼩于 4 毫秒，不⾜会⾃动增加。所以setTimeout 还是会在script end 之后打印。</p><p>不同的任务源会被分配到不同的 Task 队列中，任务源可以分为 微任务（microtask ）和 宏任务（ macrotask ）。在 ES6 规范中， microtask 称为 jobs， macrotask 称为task 。</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;script start&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#61AFEF;">setTimeout</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#E5C07B;"> console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;setTimeout&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}, </span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">new</span><span style="color:#E5C07B;"> Promise</span><span style="color:#ABB2BF;">((</span><span style="color:#E06C75;font-style:italic;">resolve</span><span style="color:#ABB2BF;">) </span><span style="color:#C678DD;">=&gt;</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;"> console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;Promise&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#61AFEF;"> resolve</span><span style="color:#ABB2BF;">()</span></span>
<span class="line"><span style="color:#ABB2BF;">}).</span><span style="color:#61AFEF;">then</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#E5C07B;"> console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;promise1&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}).</span><span style="color:#61AFEF;">then</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#E5C07B;"> console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;promise2&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">});</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;script end&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// script start =&gt; Promise =&gt; script end =&gt; promise1 =&gt; promise2 =&gt; setTime</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><ul><li>以上代码虽然 setTimeout 写在 Promise 之前，但是因为 Promise 属于微任务⽽setTimeout 属于宏任务，所以会有以上的打印。</li></ul><p>微任务包括 process.nextTick ， promise ， Object.observe ，MutationObserver</p><p>宏任务包括 script ， setTimeout ， setInterval ， setImmediate ， I/O ， UI renderin</p><p>很多⼈有个误区，认为微任务快于宏任务，其实是错误的。因为宏任务中包括 了 script ，浏览器会先执⾏⼀个宏任务，接下来有异步代码的话就先执⾏ 微任务</p><p>所以正确的⼀次 Event loop 顺序是这样的</p><ul><li>执⾏同步代码，这属于宏任务</li><li>执⾏栈为空，查询是否有微任务需要执⾏</li><li>执⾏所有微任务</li><li>必要的话渲染 UI</li><li>然后开始下⼀轮 Event loop ，执⾏宏任务中的异步代码</li></ul><p>通过上述的 Event loop 顺序可知，如果宏任务中的异步代码有⼤量的计算 并且需要操作 DOM 的话，为了更快的 界⾯响应，我们可以把操作 DOM 放 ⼊微任务中。</p><h2 id="node-的应用场景" tabindex="-1">Node 的应用场景 <a class="header-anchor" href="#node-的应用场景" aria-label="Permalink to &quot;Node 的应用场景&quot;">​</a></h2><p>特点：</p><ul><li>1、它是一个 Javascript 运⾏环境</li><li>2、依赖于 Chrome V8 引擎进⾏代码解释</li><li>3、事件驱动</li><li>4、⾮阻塞 I/O</li><li>5、单进程，单线程</li></ul><p>优点：⾼并发（最重要的优点）</p><p>缺点：</p><ul><li>1、只⽀持单核 CPU ，不能充分利用 CPU</li><li>2、可靠性低，一旦代码某个环节崩溃，整个系统都崩溃</li></ul><h2 id="面试题-1-浏览器中和-node-js-中的事件循环机制" tabindex="-1">面试题 1：浏览器中和 node.js 中的事件循环机制 <a class="header-anchor" href="#面试题-1-浏览器中和-node-js-中的事件循环机制" aria-label="Permalink to &quot;面试题 1：浏览器中和 node.js 中的事件循环机制&quot;">​</a></h2><p>当我们谈论浏览器中的事件循环和 Node.js 中的事件循环时，其实都在讨论一种处理异步任务的方式。这两者的核心思想都是在执行代码时，不必等待某些耗时的操作完成，而是继续执行其他任务，等待这些任务完成后再来处理结果。</p><h3 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h3><ul><li><strong>浏览器中的事件循环：</strong></li></ul><p>想象一下你在浏览器中点击一个按钮，触发了一个事件。浏览器会把这个事件放到一个叫做“事件队列”的地方。同时，浏览器也在做其他的事情，比如渲染页面，处理网络请求等等。当浏览器完成了当前的任务，它就会去“事件队列”里看看有没有新的事件需要处理。如果有，它就会把这个事件拿出来执行，然后再继续处理其他任务。这个循环过程就叫做事件循环。</p><p>在浏览器环境中，事件循环是处理用户交互、网络请求、渲染更新等异步操作的核心机制。</p><ul><li><strong>Node.js 中的事件循环：</strong></li></ul><p>Node.js 是用来构建服务器端应用程序的，它也有自己的事件循环机制。比如，当你在 Node.js 中发起一个网络请求时，Node.js 会把这个请求放到一个叫做“事件队列”的地方。然后，Node.js 会继续执行其他任务，比如处理数据库查询等等。当网络请求完成后，Node.js 就会去“事件队列”里找到对应的请求，然后执行相应的回调函数。这个过程和浏览器中的事件循环很相似，都是一种处理异步任务的方式。</p><h3 id="_1-浏览器中的事件循环" tabindex="-1">1. 浏览器中的事件循环 <a class="header-anchor" href="#_1-浏览器中的事件循环" aria-label="Permalink to &quot;1. 浏览器中的事件循环&quot;">​</a></h3><p>浏览器的事件循环机制遵循 HTML5 规范，主要由以下几个阶段组成：</p><ol><li><strong>宏任务队列（macrotask queue）：</strong> 宏任务队列包含一些独立的任务，比如用户交互事件、setTimeout/setInterval 定时器、网络请求等。这些任务会被依次添加到宏任务队列中等待执行。</li><li><strong>微任务队列（microtask queue）：</strong> 微任务队列包含一些相对较小的任务，比如 Promise 的回调函数、MutationObserver 等。微任务会在宏任务执行完毕后立即执行，优先级高于宏任务。</li><li><strong>渲染更新：</strong> 在每个事件循环的末尾，浏览器会执行渲染更新，更新页面的显示状态。</li></ol><p>事件循环会不断地从宏任务队列中取出任务执行，直到宏任务队列为空。在执行完一个宏任务后，会依次执行微任务队列中的所有微任务，然后进行渲染更新。这个过程循环不断，构成了浏览器的事件循环机制。</p><h3 id="_2-node-js-中的事件循环" tabindex="-1">2. Node.js 中的事件循环 <a class="header-anchor" href="#_2-node-js-中的事件循环" aria-label="Permalink to &quot;2. Node.js 中的事件循环&quot;">​</a></h3><p>Node.js 中的事件循环机制与浏览器中的有些许不同，但本质上也是为了处理异步操作。Node.js 采用了类似于浏览器事件循环的模型，但是在实现上略有差异：</p><ol><li><strong>宏任务队列（macrotask queue）：</strong> 宏任务队列中包含了一些独立的任务，比如 I/O 操作、定时器等。这些任务会被依次添加到宏任务队列中等待执行。</li><li><strong>微任务队列（microtask queue）：</strong> 与浏览器环境相同，Node.js 也有微任务队列，用于存放 Promise 的回调函数等任务。</li><li><strong>事件触发和回调执行：</strong> Node.js 中的事件循环主要通过触发事件和执行回调函数来驱动。当有事件发生时，会触发对应的事件回调函数执行。这些回调函数可能是同步的，也可能是异步的，取决于事件的类型和注册方式。</li></ol><p><strong>两者的异同：</strong></p><p>虽然浏览器中的事件循环和 Node.js 中的事件循环很相似，但它们也有一些不同之处。比如，在浏览器中，事件循环除了处理网络请求等异步任务外，还要负责渲染页面等任务；而在 Node.js 中，事件循环主要用于处理 I/O 操作，比如网络请求、文件读写等。</p>`,38),p=[e];function t(r,c,i,B,d,y){return a(),n("div",null,p)}const F=s(o,[["render",t]]);export{m as __pageData,F as default};
